SELECT CONCAT(DATE_FORMAT(l.regdate, '%Y%m%d%H%i%s'), '_', l.millisecond, '_', l.user_no) AS LOG_NO, l.user_no AS USER_NO, u.user_id AS USER_ID, u.user_name AS USER_NAME, l.menu_name AS MENU_NAME, l.job_info AS ACTION, l.user_ip AS IP_ADDR, l.regdate AS REG_DT FROM pi_userlog l LEFT JOIN pi_user u ON l.user_no = u.user_no WHERE 1=1
AND l.regdate BETWEEN CONCAT(#{fromDate}, ' 00:00:00') AND CONCAT(#{toDate}, ' 23:59:59')
AND l.log_flag = #{logFlag}
ORDER BY l.regdate DESC LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM pi_userlog l LEFT JOIN pi_user u ON l.user_no = u.user_no WHERE 1=1
AND l.regdate BETWEEN CONCAT(#{fromDate}, ' 00:00:00') AND CONCAT(#{toDate}, ' 23:59:59')
AND l.log_flag = #{logFlag}
